parameters.functionCode:
try {
  const fs = require('fs');
  const leads = JSON.parse(fs.readFileSync('D:/Content OS/pc_data/leads.json','utf8') || '[]');
  const fin = JSON.parse(fs.readFileSync('D:/Content OS/pc_data/finance.json','utf8') || '{"income":[]}');
  const income = fin.income.reduce((a,t) => a+(t.amount||0), 0);
  return [{json: {
    new_leads: leads.filter(l=>l.stage==='new').length,
    on_call: leads.filter(l=>l.stage==='call').length,
    total: leads.length,
    income: income,
    kpi: Math.round(income/20000*100)
  }}];
} catch(e) { return [{json:{error:e.message}}]; }

